    ('CHI', 'Chibi');

-- 100 units: 15 + 15 + 14 + 14 + 14 + 14 + 14.
-- Unit numbers are unique per estate: A1-A8 and B1-B7 where required.
WITH RECURSIVE
estate_capacity(estate_name, max_units) AS (
    VALUES
        ('Kibby', 15),
        ('Nancy', 15),
        ('Moriah', 14),
        ('Ebenezer', 14),
        ('Gashy', 14),
        ('Ntinda', 14),
        ('Chibi', 14)
),
series(estate_name, max_units, unit_sequence) AS (
    SELECT estate_name, max_units, 1
    FROM estate_capacity
    UNION ALL
    SELECT estate_name, max_units, unit_sequence + 1
    FROM series
    WHERE unit_sequence < max_units
)
INSERT INTO units (estate_id, unit_number, listed_monthly_rent)
SELECT
    e.estate_id,
    char(65 + CAST((s.unit_sequence - 1) / 8 AS INTEGER))
        || CAST(((s.unit_sequence - 1) % 8) + 1 AS TEXT),
    CASE ((s.unit_sequence - 1) % 12)
        WHEN 0 THEN 300000
        WHEN 1 THEN 350000
        WHEN 2 THEN 450000
        WHEN 3 THEN 550000
        WHEN 4 THEN 650000
        WHEN 5 THEN 800000
        WHEN 6 THEN 950000
        WHEN 7 THEN 1200000
        WHEN 8 THEN 1500000
        WHEN 9 THEN 1800000
        WHEN 10 THEN 2500000
        ELSE 3500000
    END
FROM series s
JOIN estates e
    ON e.estate_name = s.estate_name;

