-- Assign every generated tenant ID to one valid estate and one unique unit.
WITH assigned_tenants AS (
    SELECT
        t.tenant_id,
        CASE
            WHEN t.tenant_id BETWEEN 1 AND 15 THEN 'Kibby'
            WHEN t.tenant_id BETWEEN 16 AND 30 THEN 'Nancy'
            WHEN t.tenant_id BETWEEN 31 AND 44 THEN 'Moriah'
            WHEN t.tenant_id BETWEEN 45 AND 58 THEN 'Ebenezer'
            WHEN t.tenant_id BETWEEN 59 AND 72 THEN 'Gashy'
            WHEN t.tenant_id BETWEEN 73 AND 86 THEN 'Ntinda'
            ELSE 'Chibi'
        END AS estate_name,
        CASE
            WHEN t.tenant_id BETWEEN 1 AND 15 THEN t.tenant_id
            WHEN t.tenant_id BETWEEN 16 AND 30 THEN t.tenant_id - 15
            WHEN t.tenant_id BETWEEN 31 AND 44 THEN t.tenant_id - 30
            WHEN t.tenant_id BETWEEN 45 AND 58 THEN t.tenant_id - 44
            WHEN t.tenant_id BETWEEN 59 AND 72 THEN t.tenant_id - 58
            WHEN t.tenant_id BETWEEN 73 AND 86 THEN t.tenant_id - 72
            ELSE t.tenant_id - 86
        END AS unit_sequence
    FROM tenants t
)
INSERT INTO tenancy_assignments (
    tenant_id,
    unit_id,
    start_date,
    agreed_monthly_rent
)
SELECT
    at.tenant_id,
    u.unit_id,
    CASE
        WHEN at.tenant_id BETWEEN 1 AND 30
            THEN date('2024-06-01', '+' || (at.tenant_id - 1) || ' days')
        WHEN at.tenant_id BETWEEN 31 AND 60
            THEN date('2024-01-01', '+' || (at.tenant_id - 31) || ' days')
        WHEN at.tenant_id BETWEEN 61 AND 80
            THEN date('2026-05-01', '+' || (at.tenant_id - 61) || ' days')
        ELSE date('2024-09-01', '+' || (at.tenant_id - 81) || ' days')
    END,
    u.listed_monthly_rent
FROM assigned_tenants at
JOIN estates e
    ON e.estate_name = at.estate_name
JOIN units u
    ON u.estate_id = e.estate_id
   AND u.unit_number =
        char(65 + CAST((at.unit_sequence - 1) / 8 AS INTEGER))
        || CAST(((at.unit_sequence - 1) % 8) + 1 AS TEXT);

-- Every tenancy receives a security deposit requirement equal to one month's rent.
INSERT INTO security_deposits (tenancy_id, expected_amount)
SELECT tenancy_id, agreed_monthly_rent
FROM tenancy_assignments;

-- Arrears tenants receive January-June obligations. The other cohorts receive
-- only the applicable current months.
WITH
month_seed(month_order, rent_month, due_date) AS (
    VALUES
        (1, '2026-01', '2026-01-05'),
        (2, '2026-02', '2026-02-05'),
        (3, '2026-03', '2026-03-05'),
        (4, '2026-04', '2026-04-05'),
        (5, '2026-05', '2026-05-05'),
        (6, '2026-06', '2026-06-05')
)
INSERT INTO rent_obligations (
    tenancy_id,
    rent_month,
    due_date,
    amount_due
)
SELECT
    ta.tenancy_id,
    ms.rent_month,
    ms.due_date,
    ta.agreed_monthly_rent
FROM tenancy_assignments ta
JOIN month_seed ms
WHERE
    ta.tenant_id BETWEEN 31 AND 60
    OR (ta.tenant_id BETWEEN 1 AND 30 AND ms.month_order BETWEEN 4 AND 6)
    OR (ta.tenant_id BETWEEN 61 AND 80 AND ms.month_order = 6)
    OR (ta.tenant_id BETWEEN 81 AND 100 AND ms.month_order BETWEEN 4 AND 6);

-- Tenants 1-80 pay their deposits. Tenants 81-100 deliberately have unpaid
-- deposits while remaining current on rent.
INSERT INTO payments (
    tenant_id,
    payment_reference,
    payment_type,
    amount,
    payment_date,
    payment_method
)
SELECT
    ta.tenant_id,
    'SEC-' || printf('%06d', ta.tenant_id),
    'SECURITY_DEPOSIT',
    sd.expected_amount,
    date(ta.start_date, '+1 day'),
    CASE ta.tenant_id % 3
        WHEN 0 THEN 'MOBILE_MONEY'
        WHEN 1 THEN 'BANK_TRANSFER'
        ELSE 'CASH'
    END
FROM tenancy_assignments ta
JOIN security_deposits sd
    ON sd.tenancy_id = ta.tenancy_id
WHERE ta.tenant_id BETWEEN 1 AND 80;

INSERT INTO security_deposit_payments (
    security_deposit_id,
    payment_id,
    allocated_amount
)
SELECT
    sd.security_deposit_id,
    p.payment_id,
    sd.expected_amount
FROM tenancy_assignments ta
JOIN security_deposits sd
    ON sd.tenancy_id = ta.tenancy_id
JOIN payments p
    ON p.payment_reference = 'SEC-' || printf('%06d', ta.tenant_id)
WHERE ta.tenant_id BETWEEN 1 AND 80;

-- Create one rent payment per tenant. Its allocations cover all paid months.
-- For arrears tenants, the final 1-4 months remain unpaid.
WITH paid_obligations AS (
    SELECT
        ta.tenant_id,
        SUM(ro.amount_due) AS payment_amount,
        date(MAX(ro.due_date), '+1 day') AS payment_date
    FROM tenancy_assignments ta
JOIN rent_obligations ro
    ON ro.tenancy_id = ta.tenancy_id
    WHERE
        ta.tenant_id NOT BETWEEN 31 AND 60
        OR ro.rent_month <= printf(
            '2026-%02d',
            6 - (((ta.tenant_id - 31) % 4) + 1)
        )
    GROUP BY ta.tenant_id
)
INSERT INTO payments (
    tenant_id,
    payment_reference,
    payment_type,
    amount,
    payment_date,
    payment_method
)
SELECT
    tenant_id,
    'RENT-' || printf('%06d', tenant_id),
    'RENT',
    payment_amount,
    payment_date,
    CASE tenant_id % 3
        WHEN 0 THEN 'MOBILE_MONEY'
        WHEN 1 THEN 'BANK_TRANSFER'
        ELSE 'CASH'
    END
FROM paid_obligations;

INSERT INTO payment_allocations (
    payment_id,
    rent_obligation_id,
    allocated_amount
)
SELECT
    p.payment_id,
    ro.rent_obligation_id,
    ro.amount_due
FROM tenancy_assignments ta
JOIN rent_obligations ro
    ON ro.tenancy_id = ta.tenancy_id
JOIN payments p
    ON p.payment_reference = 'RENT-' || printf('%06d', ta.tenant_id)
WHERE
    ta.tenant_id NOT BETWEEN 31 AND 60
    OR ro.rent_month <= printf(
        '2026-%02d',
        6 - (((ta.tenant_id - 31) % 4) + 1)
    );

-- Each posted payment receives one receipt. No SMS feature is included.
INSERT INTO receipts (
    payment_id,
    receipt_number,
    issued_at,
    issued_by
)
SELECT
    p.payment_id,
    printf('%06d', p.payment_id),
    p.payment_date || 'T09:00:00',
    'SYSTEM'
FROM payments p
WHERE p.payment_status = 'POSTED';

